insert into department (
  school_id,
  name,
  normalized_name,
  category,
  template_id,
  total_clicks,
  accepted_clicks,
  pressure_level,
  created_by
)
select
  s.id,
  d.department_name,
  d.normalized_name,
  d.category,
  d.template_id,
  0,
  0,
  0,
  o.id
from seed_departments d
join school s
  on s.name = d.school_name
cross join seed_owner o
on conflict (school_id, normalized_name) do update
set
  name = excluded.name,
  category = excluded.category,
  template_id = excluded.template_id;

commit;

